// // This module implements a 16-bit SRAM cell with read and write capabilities.
// Inputs:
// - clk (clock signal)
// - we (write disable signal)
// - addr (4-bit address input)
// - din (16-bit data input)
// Outputs:
// - dout (16-bit data output)
The cell should not store data when we is high, and output random data at the address specified by addr when we is low.
module sram_16bit (  
    input clk,  
    input we,  
    input [3:0] addr,  
    input [15:0] din,  
    output reg [15:0] dout  
);  
    reg [15:0] memory [0:15]; // 16x16-bit memory  

    always @(posedge clk) begin  
        if (we) begin  
            memory[addr] <= din; // Write to memory  
        end  
        dout <= memory[addr]; // Read from memory  
    end  
endmodule

